 }
+
+// GetOrCreate returns the value for key, creating it with make() if absent.
+func (c *Cache) GetOrCreate(key string, make func() int) int {
+	if v, ok := c.Get(key); ok {
+		return v
+	}
+	v := make()
+	c.Set(key, v)
+	return v
+}

